const sales = [{region: 'A', amount: 100}, {region: 'B', amount: 200}, {region: 'A', amount: 50}];
const grouped = sales.reduce((acc, s) => {
  if (!acc[s.region]) acc[s.region] = [];
  acc[s.region].push(s);
  return acc;
}, {});

